// HasRun applies the HasEdge predicate on the "run" edge.
func HasRun() predicate.RunnerRunRequest {
	return predicate.RunnerRunRequest(func(s *sql.Selector) {
		step := sqlgraph.NewStep(
			sqlgraph.From(Table, FieldID),
			sqlgraph.Edge(sqlgraph.M2O, true, RunTable, RunColumn),
		)
		sqlgraph.HasNeighbors(s, step)
	})
}

// HasRunWith applies the HasEdge predicate on the "run" edge with a given conditions (other predicates).
func HasRunWith(preds ...predicate.RunnerRun) predicate.RunnerRunRequest {
	return predicate.RunnerRunRequest(func(s *sql.Selector) {
		step := newRunStep()
		sqlgraph.HasNeighborsWith(s, step, func(s *sql.Selector) {
			for _, p := range preds {
				p(s)
			}
		})
	})
}

// And groups predicates with the AND operator between them.
func And(predicates ...predicate.RunnerRunRequest) predicate.RunnerRunRequest {
	return predicate.RunnerRunRequest(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.RunnerRunRequest) predicate.RunnerRunRequest {
	return predicate.RunnerRunRequest(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.RunnerRunRequest) predicate.RunnerRunRequest {
	return predicate.RunnerRunRequest(sql.NotPredicates(p))
}
